import React from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { useAuth } from './context/AuthContext';

// Layout & UI Components
import Navbar from './components/Navbar';

// Page Nodes
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import DashboardPage from './pages/DashboardPage';
import GeneratePage from './pages/GeneratePage';
import PortfolioPage from './pages/PortfolioPage';

/**
 * 🛡️ Security Gate: ProtectedRoute
 * Redirects unauthenticated nodes to the Access_Gate (Login).
 */
const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  const location = useLocation();

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex flex-col items-center justify-center font-mono">
        <div className="w-10 h-10 border-2 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin mb-4" />
        <p className="text-emerald-500 text-[10px] tracking-[0.4em] animate-pulse uppercase">
          decrypting_vault_node...
        </p>
      </div>
    );
  }

  return user ? children : <Navigate to="/login" state={{ from: location }} replace />;
};

function App() {
  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white font-mono selection:bg-emerald-500 selection:text-black">
      {/* 🔔 System Notifications: Styled for the Emerald Terminal */}
      <Toaster 
        position="bottom-right"
        toastOptions={{
          style: { 
            background: '#141414', 
            color: '#fff', 
            border: '1px solid rgba(16, 185, 129, 0.2)', 
            fontSize: '11px', 
            fontFamily: 'monospace',
            borderRadius: '8px'
          },
          success: {
            iconTheme: { primary: '#10b981', secondary: '#141414' },
          },
        }}
      />

      <Navbar />

      <main className="container mx-auto px-6 py-10">
        <Routes>
          {/* Public Identity Nodes */}
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />

          {/* Secure Strategy Nodes */}
          <Route 
            path="/dashboard" 
            element={<ProtectedRoute><DashboardPage /></ProtectedRoute>} 
          />
          <Route 
            path="/generate" 
            element={<ProtectedRoute><GeneratePage /></ProtectedRoute>} 
          />
          <Route 
            path="/portfolio/:id" 
            element={<ProtectedRoute><PortfolioPage /></ProtectedRoute>} 
          />

          {/* Root Redirection */}
          <Route path="/" element={<Navigate to="/dashboard" replace />} />
          <Route path="*" element={<Navigate to="/dashboard" replace />} />
        </Routes>
      </main>

      {/* Subtle CRT Scanline Effect (Global Overlay) */}
      <div className="fixed inset-0 pointer-events-none z-[9999] opacity-[0.03] bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]" />
    </div>
  );
}

export default App;
